  <script>
    // Dark Mode Toggle
    function initDarkMode() {
      const toggle = document.getElementById('darkModeToggle');
      const html = document.documentElement;

      // Load saved preference or detect system preference
      const saved = localStorage.getItem('theme');
      const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
      const isDark = saved ? saved === 'dark' : prefersDark;

      // Set initial theme
      setTheme(isDark ? 'dark' : 'light');

      // Toggle button click
      toggle.addEventListener('click', () => {
        const current = html.getAttribute('data-theme');
        const newTheme = current === 'dark' ? 'light' : 'dark';
        setTheme(newTheme);
      });

      // Listen for system preference changes
      window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', (e) => {
        if (!localStorage.getItem('theme')) {
          setTheme(e.matches ? 'dark' : 'light');
        }
      });
    }

    function setTheme(theme) {
      const html = document.documentElement;
      html.setAttribute('data-theme', theme);
      localStorage.setItem('theme', theme);
      updateToggleIcon(theme);
    }

    function updateToggleIcon(theme) {
      const toggle = document.getElementById('darkModeToggle');
      if (toggle) {
        toggle.textContent = theme === 'dark' ? '☀️' : '🌙';
      }
    }

    // ── Detail Modal ─────────────────────────────────────
    function openDetailModal(title, meta, content, tags, linkHref) {
      document.getElementById('detailTitle').textContent = title;
      document.getElementById('detailMeta').textContent = meta;
      document.getElementById('detailContent').textContent = content;
      document.getElementById('detailLink').href = linkHref;
      const tagsEl = document.getElementById('detailTags');
      tagsEl.innerHTML = tags.map(t =>
        `<span class="text-[10px] px-2 py-0.5 rounded font-medium" style="background-color: var(--accent-light); color: var(--accent);">#${t}</span>`
      ).join('');
      document.getElementById('detailModal').classList.add('open');
    }

    function closeDetailModal() {
      document.getElementById('detailModal').classList.remove('open');
    }

    // ── Dynamic Content Load ─────────────────────────────
    async function loadLatestEntries() {
      // --- Logs (최신 2개) ---
      try {
        const res = await fetch('./logs.html');
        const doc = new DOMParser().parseFromString(await res.text(), 'text/html');
        const cards = [...doc.querySelectorAll('#logList .log-card')].slice(0, 2);
        const logContainer = document.getElementById('homeLogList');
        logContainer.innerHTML = '';
        cards.forEach(card => {
          const clone = card.cloneNode(true);
          // 클릭 시 상세 모달 오픈
          const titleEl = clone.querySelector('h3');
          const dateEl = clone.querySelector('span.text-xs');
          const contentEl = clone.querySelector('p');
          const tagEls = [...(clone.querySelectorAll('.mt-3 span') || [])];
          const title = titleEl ? titleEl.textContent.trim() : '';
          const date = dateEl ? dateEl.textContent.trim() : '';
          const content = contentEl ? contentEl.textContent.trim() : '';
          const tags = tagEls.map(s => s.textContent.trim().replace(/^#/, ''));
          clone.style.cursor = 'pointer';
          clone.addEventListener('click', (e) => { if (!e.target.closest('.edit-btn')) window.location.href = 'logs.html'; });
          // 내용 3줄로 미리보기 (서식 유지 + 페이드아웃)
          if (contentEl) { contentEl.style.cssText += '; max-height:4.5em; overflow:hidden; -webkit-mask-image:linear-gradient(to bottom, black 30%, transparent 100%); mask-image:linear-gradient(to bottom, black 30%, transparent 100%);'; }
          logContainer.appendChild(clone);
        });
      } catch(e) {
        document.getElementById('homeLogList').innerHTML = '<p class="text-xs" style="color: var(--text-tertiary);">로드 실패 — 잠시 후 새로고침</p>';
      }

      // --- Study (최신 3개, 제목+카테고리+날짜만 미리보기) ---
      try {
        const res = await fetch('./ai-study.html');
        const doc = new DOMParser().parseFromString(await res.text(), 'text/html');
        const cards = [...doc.querySelectorAll('#studyList .study-card')].slice(0, 3);
        const studyContainer = document.getElementById('homeStudyList');
        studyContainer.innerHTML = '';
        cards.forEach(card => {
          const category = card.getAttribute('data-category') || '';
          // title: <p class="...font-semibold..."> (제목은 이제 <a>가 아닌 <p>)
          const titleEl = card.querySelector('p.font-semibold') || card.querySelector('a');
          const allPs = card.querySelectorAll('p');
          const metaEl = allPs[allPs.length - 1]; // 마지막 p = 날짜·태그
          const contentEl = card.querySelector('.content-preview') || (allPs.length > 2 ? allPs[allPs.length - 2] : null);
          const title = titleEl ? titleEl.textContent.trim() : '';
          const meta = metaEl ? metaEl.textContent.trim() : '';
          const content = contentEl ? contentEl.textContent.trim() : '';
          const el = document.createElement('div');
          el.className = 'study-preview py-4';
          el.style.borderTop = '1px solid var(--border)';
          el.innerHTML = `
            <span class="text-[10px] font-semibold tracking-wider uppercase" style="color: var(--accent);">${category}</span>
            <p class="text-sm font-medium mt-1 mb-1" style="color: var(--text-primary);">${title}</p>
            <p class="text-xs" style="color: var(--text-tertiary);">${meta}</p>`;
          el.style.cursor = 'pointer';
          el.addEventListener('click', () => { window.location.href = 'ai-study.html'; });
          studyContainer.appendChild(el);
        });
      } catch(e) {
        document.getElementById('homeStudyList').innerHTML = '<p class="text-xs" style="color: var(--text-tertiary);">로드 실패 — 잠시 후 새로고침</p>';
      }
    }

    document.addEventListener('keydown', e => { if (e.key === 'Escape') closeDetailModal(); });

    // Initialize on page load
    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', () => { initDarkMode(); loadLatestEntries(); });
    } else {
      initDarkMode(); loadLatestEntries();
    }
  </script>

